#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define FLT_MAX 3.40282347e+38

inline float euclid_dist_2(__global float *pt1,
                    __global float *pt2,
                    int    numdims)
{
    float ans=0.0f;
    for (int i=0; i<numdims; i++)
        ans += (pt1[i]-pt2[i]) * (pt1[i]-pt2[i]);
    return ans;
}

inline int find_nearest_point(__global float  *pt,          
                       int     nfeatures,
                       __global float **pts,         
                       int     npts)
{
    int index = 0;
    float min_dist=FLT_MAX;
    for (int i=0; i<npts; i++) {
        float dist;
        dist = euclid_dist_2(pt, pts[i], nfeatures);  
        if (dist < min_dist) {
            min_dist = dist;
            index    = i;
        }
    }
    return index;
}

__kernel void kmeans_assign_clusters(
    __global float *features,       // flattened features array: npoints * nfeatures
    int nfeatures,
    int npoints,
    __global float *clusters,       // flattened clusters array: nclusters * nfeatures
    int nclusters,
    __global int *membership,
    __global int *partial_new_centers_len,
    __global float *partial_new_centers,
    int nthreads,
    int tid,
    __global float *delta_out)
{
    int gid = get_global_id(0);
    if (gid >= npoints) return;

    // Compute pointer to feature vector
    __global float *pt = &features[gid * nfeatures];

    // Find nearest cluster
    int index = 0;
    float min_dist = FLT_MAX;
    for (int i=0; i<nclusters; i++) {
        __global float *cluster_pt = &clusters[i * nfeatures];
        float dist = 0.0f;
        for (int j=0; j<nfeatures; j++) {
            float diff = pt[j] - cluster_pt[j];
            dist += diff * diff;
        }
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }

    // Update delta if membership changed
    int old_membership = membership[gid];
    if (old_membership != index) {
        // atomic add to delta_out
        atomic_add((volatile __global int*)delta_out, 1);
    }
    membership[gid] = index;

    // Update partial new centers len and sums
    int offset_len = tid * nclusters + index;
    atomic_inc(&partial_new_centers_len[offset_len]);

    int offset_center = tid * nclusters * nfeatures + index * nfeatures;
    for (int j=0; j<nfeatures; j++) {
        atomic_add(&partial_new_centers[offset_center + j], pt[j]);
    }
}

__kernel void kmeans_reduce_centers(
    __global int *partial_new_centers_len,
    __global float *partial_new_centers,
    int nthreads,
    int nclusters,
    int nfeatures,
    __global int *new_centers_len,
    __global float *new_centers)
{
    int cid = get_global_id(0);
    if (cid >= nclusters) return;

    int sum_len = 0;
    for (int t=0; t<nthreads; t++) {
        sum_len += partial_new_centers_len[t * nclusters + cid];
        partial_new_centers_len[t * nclusters + cid] = 0;
    }
    new_centers_len[cid] = sum_len;

    for (int j=0; j<nfeatures; j++) {
        float sum_val = 0.0f;
        for (int t=0; t<nthreads; t++) {
            sum_val += partial_new_centers[t * nclusters * nfeatures + cid * nfeatures + j];
            partial_new_centers[t * nclusters * nfeatures + cid * nfeatures + j] = 0.0f;
        }
        new_centers[cid * nfeatures + j] = sum_val;
    }
}

__kernel void kmeans_update_clusters(
    __global int *new_centers_len,
    __global float *new_centers,
    int nclusters,
    int nfeatures,
    __global float *clusters)
{
    int cid = get_global_id(0);
    if (cid >= nclusters) return;

    int len = new_centers_len[cid];
    if (len > 0) {
        for (int j=0; j<nfeatures; j++) {
            clusters[cid * nfeatures + j] = new_centers[cid * nfeatures + j] / (float)len;
            new_centers[cid * nfeatures + j] = 0.0f;
        }
    }
    new_centers_len[cid] = 0;
}
